כשיוצרים אלמנט SVG ב-JS, חובה להשתמש ב-createElementNS ולא ב-createElement הרגיל!

הנה הדרך הנכונה:
const svgNS = 'http://www.w3.org/2000/svg';
const circle = document.createElementNS(svgNS, 'circle');
circle.setAttribute('cx', 50);
circle.setAttribute('cy', 50);
circle.setAttribute('r', 20);
circle.setAttribute('fill', 'tomato');
svg.appendChild(circle);

לתנועה חלקה השתמש ב-requestAnimationFrame במקום ב-setInterval:

let x = 0;
function animate() {
  x += 2;
  circle.setAttribute('cx', x);
  if (x < 300) requestAnimationFrame(animate);
}
requestAnimationFrame(animate);
